import { describe, expect, it } from "vitest";
import { detectReplayCapabilities, isReplayLanguage, isVersionAtLeast, REPLAY_CAPABILITY_MIN_VERSIONS, } from "./replayCapabilities.js";
describe("isVersionAtLeast", () => {
    it("returns false for a null version", () => {
        expect(isVersionAtLeast(null, "0.13.5")).toBe(false);
    });
    it("returns true for an equal version", () => {
        expect(isVersionAtLeast("0.13.5", "0.13.5")).toBe(true);
    });
    it("returns true for a newer version", () => {
        expect(isVersionAtLeast("0.20.0", "0.13.5")).toBe(true);
        expect(isVersionAtLeast("0.13.6", "0.13.5")).toBe(true);
    });
    it("returns false for an older version", () => {
        expect(isVersionAtLeast("0.13.4", "0.13.5")).toBe(false);
        expect(isVersionAtLeast("0.9.0", "0.13.5")).toBe(false);
    });
    it("treats a pre-release as below the matching stable floor", () => {
        expect(isVersionAtLeast("0.13.5-beta.1", "0.13.5")).toBe(false);
    });
    it("treats a pre-release as at least an earlier floor", () => {
        expect(isVersionAtLeast("0.13.5-beta.1", "0.13.4")).toBe(true);
    });
});
describe("isReplayLanguage", () => {
    it("includes the three replay SDKs and excludes Go", () => {
        expect(isReplayLanguage("typescript")).toBe(true);
        expect(isReplayLanguage("python")).toBe(true);
        expect(isReplayLanguage("ruby")).toBe(true);
        expect(isReplayLanguage("go")).toBe(false);
    });
});
describe("detectReplayCapabilities", () => {
    it("marks every capability false for a null version", () => {
        expect(detectReplayCapabilities("typescript", null)).toEqual({
            supportsExperimentGroups: false,
            supportsDatasetId: false,
            supportsCodeChanges: false,
            supportsReplayTraceIds: false,
            supportsInputAdapters: false,
            supportsExperimentNames: false,
        });
    });
    it("marks every capability false for an ancient version", () => {
        const caps = detectReplayCapabilities("typescript", "0.9.0");
        expect(Object.values(caps).every((v) => v === false)).toBe(true);
    });
    it("gates TS replay trace IDs at 0.13.5, not 0.13.6 (off-by-one guard)", () => {
        // 0.13.5 surfaces ReplayItem.traceId but not experiment groups yet.
        const at1305 = detectReplayCapabilities("typescript", "0.13.5");
        expect(at1305.supportsReplayTraceIds).toBe(true);
        expect(at1305.supportsExperimentGroups).toBe(false);
        const at1306 = detectReplayCapabilities("typescript", "0.13.6");
        expect(at1306.supportsReplayTraceIds).toBe(true);
        expect(at1306.supportsExperimentGroups).toBe(true);
    });
    it("gates dataset attribution at 0.20.0 across languages", () => {
        expect(detectReplayCapabilities("typescript", "0.19.0").supportsDatasetId).toBe(false);
        expect(detectReplayCapabilities("typescript", "0.20.0").supportsDatasetId).toBe(true);
        expect(detectReplayCapabilities("python", "0.20.0").supportsDatasetId).toBe(true);
        expect(detectReplayCapabilities("ruby", "0.20.0").supportsDatasetId).toBe(true);
    });
    it("gates input adapters at 0.16.0", () => {
        expect(detectReplayCapabilities("python", "0.15.0").supportsInputAdapters).toBe(false);
        expect(detectReplayCapabilities("python", "0.16.0").supportsInputAdapters).toBe(true);
    });
    it("reports full capability for the current SDK floors", () => {
        // A version at or above every floor (experiment names are the highest).
        for (const language of ["typescript", "python", "ruby"]) {
            const caps = detectReplayCapabilities(language, "0.27.0");
            expect(Object.values(caps).every((v) => v === true)).toBe(true);
        }
    });
    it("honors per-language floors for code changes", () => {
        // Ruby's codeChanges floor (0.10.5) is below TS's (0.11.5).
        expect(detectReplayCapabilities("ruby", "0.10.5").supportsCodeChanges).toBe(true);
        expect(detectReplayCapabilities("typescript", "0.10.5").supportsCodeChanges).toBe(false);
    });
    it("covers every capability key in the version map", () => {
        for (const language of ["typescript", "python", "ruby"]) {
            expect(Object.keys(REPLAY_CAPABILITY_MIN_VERSIONS[language]).sort()).toEqual([
                "supportsCodeChanges",
                "supportsDatasetId",
                "supportsExperimentGroups",
                "supportsExperimentNames",
                "supportsInputAdapters",
                "supportsReplayTraceIds",
            ]);
        }
    });
});
